input.command:
RUN_ID="$ZEALT_RUN_ID"
LOCAL=$(echo "$MAGICBELL_EMAIL" | cut -d'@' -f1)
DOMAIN=$(echo "$MAGICBELL_EMAIL" | cut -d'@' -f2)
RECIPIENT_EMAIL="${LOCAL}+trigger-cli-${RUN_ID}@${DOMAIN}"
WORKFLOW_KEY="wf-trigger-cli-${RUN_ID}"

WORKFLOW_JSON=$(cat <<EOF
{
  "key": "${WORKFLOW_KEY}",
  "name": "Workflow Trigger CLI ${RUN_ID}",
  "steps": [
    {
      "type": "broadcast",
      "input": {
        "title": "Workflow Trigger CLI - {{ marker }}",
        "content": "This is a broadcast notification for workflow run triggered by the MagicBell CLI.",
        "recipients": [
          {
            "email": "{{ recipient_email }}"
          }
        ]
      }
    }
  ]
}
EOF
)

echo "$WORKFLOW_JSON"
echo "---"
magicbell workflow save --data "$WORKFLOW_JSON"

